async (params, browser) => {
  // Open page
  await browser.open(`${params.post_url}`)

  // Wait for content
  await browser.waitForSelector('#titletextonly, .postingtitletext, .posting-title, body', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const title = document.querySelector('#titletextonly, .postingtitletext, .posting-title')?.textContent?.trim()||''; const price = document.querySelector('.price, .postingtitletext .price, .priceinfo')?.textContent?.trim()||''; const body = document.querySelector('#postingbody, .posting-body')?.textContent?.trim()?.replace('QR Code Link to This Post','')?.trim()?.substring(0,2000)||''; const attrs = {}; document.querySelectorAll('.attrgroup span, .mapAndAttrs .attrgroup span').forEach(s => { const text = s.textContent.trim(); const parts = text.split(':'); if(parts.length===2) attrs[parts[0].trim().toLowerCase()]=parts[1].trim(); else if(text) attrs[text.toLowerCase()]='yes'; }); const images = Array.from(document.querySelectorAll('#thumbs a, .swipe img, .gallery img, .slide img')).slice(0,10).map(el=>el.href||el.src||'').filter(Boolean); const loc = document.querySelector('.mapaddress, [class*="mapaddress"]')?.textContent?.trim()||''; const posted = document.querySelector('time')?.textContent?.trim()||''; return { title, price, description: body, attributes: attrs, images, location: loc, posted, url: window.location.href }`)

  return page_data
}
